function solve(n: number, edges: number[][], k: number): number {
    class DSU {
        parent: number[];
        rank: number[];
        count: number;
        constructor(n: number) {
            this.parent = Array(n).fill(0).map((_, i) => i);
            this.rank = Array(n).fill(0);
            this.count = n;
        }
        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }
        union(x: number, y: number): boolean {
            const rootX = this.find(x);
            const rootY = this.find(y);
            if (rootX === rootY) return false;
            if (this.rank[rootX] < this.rank[rootY]) {
                this.parent[rootX] = rootY;
            } else {
                this.parent[rootY] = rootX;
                if (this.rank[rootX] === this.rank[rootY]) {
                    this.rank[rootX]++;
                }
            }
            this.count--;
            return true;
        }
        get_components_count(): number {
            return this.count;
        }
    }

    function isPossible(X: number): boolean {
        const dsu = new DSU(n);
        for (const [u, v, w] of edges) {
            if (w <= X) {
                dsu.union(u, v);
            }
        }
        return dsu.get_components_count() <= k;
    }

    let low = 0;
    let high = 0;
    for (const [u, v, w] of edges) {
        if (w > high) high = w;
    }
    let answer = high;
    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (isPossible(mid)) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}

