class DSU {
    val parent: Array[Int]
    val rank: Array[Int]
    var count: Int

    def this(n: Int) {
        parent = Array.range(0, n, 1)
        rank = Array.fill(n)(0)
        count = n
    }

    def find(x: Int): Int = {
        if (parent(x) != x) {
            parent(x) = find(parent(x))
        }
        parent(x)
    }

    def union(x: Int, y: Int): Boolean = {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX == rootY) return false
        if (rank(rootX) < rank(rootY)) {
            parent(rootX) = rootY
        } else {
            parent(rootY) = rootX
            if (rank(rootX) == rank(rootY)) {
                rank(rootX) += 1
            }
        }
        count -= 1
        true
    }

    def getComponentsCount(): Int = count
}

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
    var maxWeight = 0L
    for (edge <- edges) {
        if (edge(2) > maxWeight) {
            maxWeight = edge(2)
        }
    }

    var low = 0L
    var high = maxWeight
    var answer = maxWeight

    def isPossible(X: Long): Boolean = {
        val dsu = new DSU(n.toInt)
        for (edge <- edges) {
            val u = edge(0).toInt
            val v = edge(1).toInt
            val w = edge(2)
            if (w <= X) {
                dsu.union(u, v)
            }
        }
        dsu.getComponentsCount() <= k.toInt
    }

    while (low <= high) {
        val mid = (low + high) / 2
        if (isPossible(mid)) {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    answer
}
