class DSU {
    val parent: Array[Int]
    val rank: Array[Int]
    var count: Int

    def this(n: Int) {
        parent = Array.range(0, n, 1)
        rank = Array.fill(n)(0)
        count = n
    }

    def find(x: Int): Int = {
        if (parent(x) != x) {
            parent(x) = find(parent(x))
        }
        parent(x)
    }

    def union(x: Int, y: Int): Boolean = {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX == rootY) return false
        if (rank(rootX) < rank(rootY)) {
            parent(rootX) = rootY
        } else {
            parent(rootY) = rootX
            if (rank(rootX) == rank(rootY)) {
                rank(rootX) += 1
            }
        }
        count -= 1
        true
    }

    def getComponentsCount(): Int = count
}

